    gen_random_uuid(),
    '10000000-0000-0000-0000-000000000001',
    '30000000-0000-0000-0000-000000000001',
    '40000000-0000-0000-0000-000000000001',
    'A',
    r.row_num::text,
    c.col_num::text,
    'A-' || r.row_num::text || '-' || c.col_num::text,
